action.storedProcedure:
CREATE OR REPLACE  PROCEDURE "STP_BTN_ALT_CFOP_AD_NATTPOCFO2" (
       P_CODUSU NUMBER,        -- Código do usuário logado
       P_IDSESSAO VARCHAR2,    -- Identificador da execução. Serve para buscar informações dos parâmetros/campos da execução.
       P_QTDLINHAS NUMBER,     -- Informa a quantidade de registros selecionados no momento da execução.
       P_MENSAGEM OUT VARCHAR2 -- Caso seja passada uma mensagem aqui, ela será exibida como uma informação ao usuário.
) AS
       PARAM_CODCFO VARCHAR2(4000);
       FIELD_CODCFO VARCHAR2(4000);
       FIELD_CODTIPOPER NUMBER;
       FIELD_NUNOTA NUMBER;
       V_MSGERRO VARCHAR2(4000);
BEGIN

       -- Os valores informados pelo formulário de parâmetros, podem ser obtidos com as funções:
       --     ACT_INT_PARAM
       --     ACT_DEC_PARAM
       --     ACT_TXT_PARAM
       --     ACT_DTA_PARAM
       -- Estas funções recebem 2 argumentos:
       --     ID DA SESSÃO - Identificador da execução (Obtido através de P_IDSESSAO))
       --     NOME DO PARAMETRO - Determina qual parametro deve se deseja obter.

       /* Objetivo: Atualizar CFOP dos itens da nota selecionada */

       PARAM_CODCFO := ACT_TXT_PARAM(P_IDSESSAO, 'CODCFO');

       FOR I IN 1..P_QTDLINHAS -- Este loop permite obter o valor de campos dos registros envolvidos na execução.
       LOOP                    -- A variável "I" representa o registro corrente.
              -- Para obter o valor dos campos utilize uma das seguintes funções:
              --     ACT_INT_FIELD (Retorna o valor de um campo tipo NUMÉRICO INTEIRO))
              --     ACT_DEC_FIELD (Retorna o valor de um campo tipo NUMÉRICO DECIMAL))
              --     ACT_TXT_FIELD (Retorna o valor de um campo tipo TEXTO),
              --     ACT_DTA_FIELD (Retorna o valor de um campo tipo DATA)
              -- Estas funções recebem 3 argumentos:
              --     ID DA SESSÃO - Identificador da execução (Obtido através do parâmetro P_IDSESSAO))
              --     NÚMERO DA LINHA - Relativo a qual linha selecionada.
              --     NOME DO CAMPO - Determina qual campo deve ser obtido.
              FIELD_CODCFO := ACT_TXT_FIELD(P_IDSESSAO, I, 'CODCFO');
              FIELD_CODTIPOPER := ACT_INT_FIELD(P_IDSESSAO, I, 'CODTIPOPER');
              FIELD_NUNOTA := ACT_INT_FIELD(P_IDSESSAO, I, 'NUNOTA');

              /* SE NAO INFORMOU A CFOP */
              IF NVL(PARAM_CODCFO,0) = 0 THEN


                     V_MSGERRO := '<p align="left"><font size="12" face="arial"><br><b>Atenção:  </b> Erro na atualização!<br><br>' ||
                                  '<b>Motivo: </b> Não é permitido informar CFOP zero.<br><br>' ||
                                  '<b>Solução: </b>Informe uma CFOP válida e em seguida tente novamente.<br><br>';

                     RAISE_APPLICATION_ERROR(-20101, V_MSGERRO);

              END IF;             

              /* ATUALIZA CFOP NA TGFITE */
              UPDATE TGFITE SET CODCFO = PARAM_CODCFO
               WHERE NUNOTA = FIELD_NUNOTA
                 AND CODCFO = FIELD_CODCFO;


       END LOOP;

       P_MENSAGEM := 'Atualização realizada com sucesso!';

END;

CREATE OR REPLACE PROCEDURE "STP_BTN_ATUAL_TOP" ( P_CODUSU NUMBER, P_IDSESSAO VARCHAR2, P_QTDLINHAS NUMBER, P_MENSAGEM OUT VARCHAR2 ) AS -- Campos vindos da linha selecionada (da sua VIEW) FIELD_NUNOTA NUMBER; -- << chave do cabeçalho FIELD_CODTIPOPER NUMBER; -- TOP atual exibida na linha FIELD_CODCFO VARCHAR2(4000); -- CFOP do item (se a sua view expõe)
-- Calculados V_CODTIPOPERNOVA TGFTOP.CODTIPOPER%TYPE; -- TOP de destino (mapeamento) V_DHTOP TGFTOP.DHALTER%TYPE; -- última versão da TOP destino V_TIPMOV TGFTOP.TIPMOV%TYPE;
V_MSGERRO VARCHAR2(4000); BEGIN FOR I IN 1..P_QTDLINHAS LOOP -------------------------------------------------------------------- -- 1) Ler os valores da LINHA selecionada na grid (vêm da sua VIEW) -------------------------------------------------------------------- -- OBS: se na sua view o campo se chama NROUNICO, troque abaixo: -- V_NUNOTA := ACT_INT_FIELD(P_IDSESSAO, I, 'NROUNICO'); FIELD_CODCFO := ACT_TXT_FIELD(P_IDSESSAO, I, 'CODCFO'); FIELD_CODTIPOPER := ACT_INT_FIELD(P_IDSESSAO, I, 'CODTIPOPER'); FIELD_NUNOTA := ACT_INT_FIELD(P_IDSESSAO, I, 'NUNOTA');
IF FIELD_NUNOTA IS NULL THEN RAISE_APPLICATION_ERROR(-20100, 'A view precisa expor a chave (NUNOTA/NROUNICO) para atualizar apenas as linhas selecionadas.'); END IF;
-------------------------------------------------------------------- -- 2) Descobrir a TOP de destino (tabela de mapeamento AD_NATTPOCFO) -------------------------------------------------------------------- BEGIN SELECT CODTIPOPERNOVA INTO V_CODTIPOPERNOVA FROM AD_NATTPOCFO WHERE CODTIPOPER = FIELD_CODTIPOPER AND CODCFO = FIELD_CODCFO; -- se o seu mapeamento não usa CFOP da linha, -- substitua aqui pelo campo/param correto EXCEPTION WHEN NO_DATA_FOUND THEN V_MSGERRO := 'Sem mapeamento em AD_NATTPOCFO para CODTIPOPER='||FIELD_CODTIPOPER|| ' e CODCFO='||FIELD_CODCFO||' (NUNOTA '||FIELD_NUNOTA||').'; RAISE_APPLICATION_ERROR(-20101, V_MSGERRO); WHEN TOO_MANY_ROWS THEN V_MSGERRO := 'Mapeamento duplicado em AD_NATTPOCFO para CODTIPOPER='||FIELD_CODTIPOPER|| ' e CODCFO='||FIELD_CODCFO||' (NUNOTA '||FIELD_NUNOTA||').'; RAISE_APPLICATION_ERROR(-20102, V_MSGERRO); END;
-------------------------------------------------------------------- -- 3) Buscar a ÚLTIMA versão dessa TOP (mesma DH para TIPMOV e DHTIPOPER) -------------------------------------------------------------------- SELECT MAX(t.DHALTER) KEEP (DENSE_RANK LAST ORDER BY t.DHALTER) AS DH, MAX(t.TIPMOV) KEEP (DENSE_RANK LAST ORDER BY t.DHALTER) AS TP INTO V_DHTOP, V_TIPMOV FROM TGFTOP t WHERE t.CODTIPOPER = V_CODTIPOPERNOVA;
IF V_DHTOP IS NULL THEN RAISE_APPLICATION_ERROR(-20103, 'TOP destino '||V_CODTIPOPERNOVA||' sem versão em TGFTOP.'); END IF;
-------------------------------------------------------------------- -- 4) Atualizar SOMENTE a nota selecionada (pelo cabeçalho TGFCAB) -- Mantemos salvaguardas: só troca se TOP atual confere e a nota tem item com o CFOP -------------------------------------------------------------------- UPDATE TGFCAB C SET C.CODTIPOPER = V_CODTIPOPERNOVA, C.DHTIPOPER = V_DHTOP, C.TIPMOV = V_TIPMOV WHERE C.NUNOTA = FIELD_NUNOTA AND C.CODTIPOPER = FIELD_CODTIPOPER AND EXISTS ( SELECT 1 FROM TGFITE I WHERE I.NUNOTA = C.NUNOTA AND I.CODCFO = FIELD_CODCFO ); -- Se quiser garantir que pelo menos 1 linha foi afetada, você pode checar SQL%ROWCOUNT aqui. END LOOP;
P_MENSAGEM := 'Atualização realizada com sucesso apenas para as linhas selecionadas.'; EXCEPTION WHEN OTHERS THEN IF SQLCODE BETWEEN -20999 AND -20000 THEN RAISE; ELSE RAISE_APPLICATION_ERROR(-20199, 'Falha na atualização: '||SQLCODE||' - '||SQLERRM); END IF; END;

CREATE OR REPLACE  PROCEDURE "STP_BTN_ATUAL_NAT_TPO_CFO" (
       P_CODUSU NUMBER,        -- Código do usuário logado
       P_IDSESSAO VARCHAR2,    -- Identificador da execução. Serve para buscar informações dos parâmetros/campos da execução.
       P_QTDLINHAS NUMBER,     -- Informa a quantidade de registros selecionados no momento da execução.
       P_MENSAGEM OUT VARCHAR2 -- Caso seja passada uma mensagem aqui, ela será exibida como uma informação ao usuário.
) AS
       FIELD_CODTIPOPER NUMBER;
       FIELD_CODCFO     VARCHAR2(4000);
       V_MSGERRO        VARCHAR2(4000);
       V_CODNAT         TGFNAT.CODNAT%TYPE;
BEGIN

       -- Os valores informados pelo formulário de parâmetros, podem ser obtidos com as funções:
       --     ACT_INT_PARAM
       --     ACT_DEC_PARAM
       --     ACT_TXT_PARAM
       --     ACT_DTA_PARAM
       -- Estas funções recebem 2 argumentos:
       --     ID DA SESSÃO - Identificador da execução (Obtido através de P_IDSESSAO))
       --     NOME DO PARAMETRO - Determina qual parametro deve se deseja obter.

       /* Objetivo: Atualizar naturezas de notas de acordo com a TOP e CFOP */

       FOR I IN 1..P_QTDLINHAS -- Este loop permite obter o valor de campos dos registros envolvidos na execução.
       LOOP                    -- A variável "I" representa o registro corrente.
              -- Para obter o valor dos campos utilize uma das seguintes funções:
              --     ACT_INT_FIELD (Retorna o valor de um campo tipo NUMÉRICO INTEIRO))
              --     ACT_DEC_FIELD (Retorna o valor de um campo tipo NUMÉRICO DECIMAL))
              --     ACT_TXT_FIELD (Retorna o valor de um campo tipo TEXTO),
              --     ACT_DTA_FIELD (Retorna o valor de um campo tipo DATA)
              -- Estas funções recebem 3 argumentos:
              --     ID DA SESSÃO - Identificador da execução (Obtido através do parâmetro P_IDSESSAO))
              --     NÚMERO DA LINHA - Relativo a qual linha selecionada.
              --     NOME DO CAMPO - Determina qual campo deve ser obtido.
              FIELD_CODTIPOPER := ACT_INT_FIELD(P_IDSESSAO, I, 'CODTIPOPER');
              FIELD_CODCFO := ACT_TXT_FIELD(P_IDSESSAO, I, 'CODCFO');

              /* BUSCA NATUREZA QUE SERA UTILIZADA PARA ATUALIZAR NOTAS */
              SELECT CODNAT
                INTO V_CODNAT
                FROM AD_NATTPOCFO
               WHERE CODTIPOPER = FIELD_CODTIPOPER
                 AND CODCFO = FIELD_CODCFO;

              /* SE NAO INFORMOU A NATUREZA */
              IF NVL(V_CODNAT,0) = 0 THEN


                     V_MSGERRO := '<p align="left"><font size="12" face="arial"><br><b>Atenção:  </b> Erro na atualização!<br><br>' ||
                                  '<b>Motivo: </b> Não foi informada a natureza para a TOP ' || FIELD_CODTIPOPER || ' e CFOP ' || FIELD_CODCFO || '.<br><br>' ||
                                  '<b>Solução: </b>Informe a natureza e em seguida tente novamente.<br><br>';

                     RAISE_APPLICATION_ERROR(-20101, V_MSGERRO);

              END IF;

              /* ATUALIZA TGFCAB */
              UPDATE TGFCAB SET CODNAT = V_CODNAT
               WHERE EXISTS (SELECT 1
                               FROM TGFCAB C
                               INNER JOIN TGFITE I ON (C.NUNOTA = I.NUNOTA)
                              WHERE C.NUNOTA = TGFCAB.NUNOTA
                                AND C.CODTIPOPER = FIELD_CODTIPOPER
                                AND I.CODCFO = FIELD_CODCFO);

              /* ATUALIZA FINANCEIRO */
              UPDATE TGFFIN SET CODNAT = V_CODNAT
               WHERE EXISTS (SELECT 1
                               FROM TGFCAB C
                               INNER JOIN TGFITE I ON (C.NUNOTA = I.NUNOTA)
                              WHERE C.NUNOTA = TGFFIN.NUNOTA
                                AND C.CODTIPOPER = FIELD_CODTIPOPER
                                AND I.CODCFO = FIELD_CODCFO);


       END LOOP;

       P_MENSAGEM := 'Atualização realizada com sucesso!';

END;

CREATE OR REPLACE PROCEDURE "STP_BTN_DADOS_AD_NATTPOCFO" ( P_CODUSU NUMBER, -- Código do usuário logado P_IDSESSAO VARCHAR2, -- Identificador da execução. Serve para buscar informações dos parâmetros/campos da execução. P_QTDLINHAS NUMBER, -- Informa a quantidade de registros selecionados no momento da execução. P_MENSAGEM OUT VARCHAR2 -- Caso seja passada uma mensagem aqui, ela será exibida como uma informação ao usuário. ) AS FIELD_CODTIPOPER NUMBER; FIELD_CODCFO VARCHAR2(4000); BEGIN
-- Os valores informados pelo formulário de parâmetros, podem ser obtidos com as funções: -- ACT_INT_PARAM -- ACT_DEC_PARAM -- ACT_TXT_PARAM -- ACT_DTA_PARAM -- Estas funções recebem 2 argumentos: -- ID DA SESSÃO - Identificador da execução (Obtido através de P_IDSESSAO)) -- NOME DO PARAMETRO - Determina qual parametro deve se deseja obter.
/* Objetivo: Inserir TOPs e CFOPs na tabela de atualizacao de naturezas AD_NATTPOCFO */
/* INSERE TOPS E CFOS NA TABELA AD_NATTPOCFO */ INSERT INTO AD_NATTPOCFO (CODTIPOPER, CODCFO) SELECT DISTINCT CAB.CODTIPOPER, ITE.CODCFO FROM TGFCAB CAB INNER JOIN TGFITE ITE ON (CAB.NUNOTA = ITE.NUNOTA) WHERE NOT EXISTS (SELECT 1 FROM AD_NATTPOCFO WHERE CODTIPOPER = CAB.CODTIPOPER AND CODCFO = ITE.CODCFO) AND CAB.TIPMOV <> 'Z';
P_MENSAGEM := 'Dados carregados com sucesso!';
END;
